    // Team value propositions
    team_value1_p: "Trabalhamos com um número deliberadamente seleccionado de clientes cada trimestre, garantindo que cada programa recebe a profundidade de atenção que merece.",
    team_value2_p: "Cada recomendação é fundamentada em investigação revista por pares, frameworks validados e dados de milhares de progressões de carreira executiva reais.",
    team_value3_p: "A nossa equipa viveu dentro dos sistemas que os nossos clientes estão a navegar. Essa perspectiva não é ensinável — e é a base da nossa vantagem.",
    // Team architects subtitle
    team_architects_subtitle: "Desde a identificação inicial de alto potencial até à colocação executiva sénior, os nossos arquitectos especializados cobrem cada etapa da jornada de carreira em cinco cidades globais.",
    // Architects team members
    tm_james_name: "James Laurent",
    tm_james_role: "Arquitecto de Carreira Executiva",
    tm_james_bio: "Ex-Director Executivo numa consultoria Big Four. 18 anos a engenheirar transições C-Suite na Europa e Américas. Especializado em reposicionamento de líderes seniores, negociação de compensação e estratégia de visibilidade ao nível da administração.",
    tm_james_location: "Paris & Nova Iorque",
    tm_priya_name: "Priya Sharma",
    tm_priya_role: "Estratega Especialista de Crescimento de Carreira",
    tm_priya_bio: "MSc Psicologia Organizacional, UCL. Especialista em diagnósticos de talento de alto potencial, análise de velocidade de carreira e frameworks de promoção acelerada para managers na threshold de Director e VP. 12 anos em estratégia de talento.",
    tm_priya_location: "Londres",
    tm_thomas_name: "Thomas Reed",
    tm_thomas_role: "Arquitecto de Potencial Inicial",
    tm_thomas_bio: "10 anos identificando e desenvolvendo high-potentials em fase inicial em empresas Fortune 500 de tecnologia e serviços financeiros. Especialista em transição de primeira liderança, mapeamento de ambição, construção de fundação de carreira e visibilidade corporativa desde o dia um.",
    tm_thomas_location: "Nova Iorque",
    tm_isabel_name: "Isabel Castillo",
    tm_isabel_role: "Directora de Colocação de Talento",
    tm_isabel_bio: "Ex-Head de Talento Executivo numa empresa global Fortune 100. Lidera a nossa estratégia de colocação directa, relações com comissões de recrutamento e posicionamento do mercado executivo. Rede extensa em Ibéria, América Latina e EUA.",
