    tm_ana_role: "Directora de Crecimiento de Potencial",
    tm_ana_bio: "Doctorada en Comportamiento Organizacional, London Business School. Lidera nuestros marcos de diagnóstico basados en evidencia y metodología de feedback 360. Investigadora publicada en identificación de talento de alto potencial y velocidad de carrera.",
    tm_ana_location: "Londres",
